const data = $input.all().map(i => i.json);

const byPillar = {
  Health: {posts: [], total: 0, identity_signals: {saves: 0, repeat_viewers: 0, follower_conv: 0}, top_topics: {}, platforms: {}},
  Wealth: {posts: [], total: 0, identity_signals: {saves: 0, repeat_viewers: 0, follower_conv: 0}, top_topics: {}, platforms: {}},
  Wisdom: {posts: [], total: 0, identity_signals: {saves: 0, repeat_viewers: 0, follower_conv: 0}, top_topics: {}, platforms: {}},
  Integration: {posts: [], total: 0, identity_signals: {saves: 0, repeat_viewers: 0, follower_conv: 0}, top_topics: {}, platforms: {}}
};

data.forEach(p => {
  const pillar = p.pillar;
  if (!byPillar[pillar]) return;

  byPillar[pillar].posts.push(p);
  byPillar[pillar].total += p.engagement_score || 0;

  // Identity signals
  byPillar[pillar].identity_signals.saves += p.saves || 0;
  byPillar[pillar].identity_signals.repeat_viewers += p.repeat_viewers || 0;
  byPillar[pillar].identity_signals.follower_conv += p.new_followers || 0;

  // Topic tracking
  const topic = p.topic || 'unknown';
  if (!byPillar[pillar].top_topics[topic]) {
    byPillar[pillar].top_topics[topic] = {count: 0, total_score: 0, identity_score: 0};
  }
  byPillar[pillar].top_topics[topic].count++;
  byPillar[pillar].top_topics[topic].total_score += p.engagement_score || 0;
  byPillar[pillar].top_topics[topic].identity_score += (p.saves || 0) + (p.new_followers || 0);

  // Platform performance per pillar
  const platform = p.platform;
  if (!byPillar[pillar].platforms[platform]) {
    byPillar[pillar].platforms[platform] = {total: 0, count: 0, identity: 0};
  }
  byPillar[pillar].platforms[platform].total += p.engagement_score || 0;
  byPillar[pillar].platforms[platform].count++;
  byPillar[pillar].platforms[platform].identity += (p.saves || 0) + (p.new_followers || 0);
});

// Calculate averages and detect philosophical saturation
Object.keys(byPillar).forEach(pillar => {
  const d = byPillar[pillar];
  d.avg_score = d.posts.length > 0 ? Math.round(d.total / d.posts.length) : 0;

  // Top 20% topics
  d.top_20_topics = Object.entries(d.top_topics)
    .map(([topic, stats]) => ({
      topic,
      count: stats.count,
      avg_score: Math.round(stats.total_score / stats.count),
      identity_score: stats.identity_score
    }))
    .sort((a, b) => b.identity_score - a.identity_score)
    .slice(0, Math.ceil(Object.keys(d.top_topics).length * 0.2));

  // Platform identity conversion
  d.best_platforms = Object.entries(d.platforms)
    .map(([platform, stats]) => ({
      platform,
      avg_score: Math.round(stats.total / stats.count),
      identity_ratio: stats.identity / stats.count
    }))
    .sort((a, b) => b.identity_ratio - a.identity_ratio)
    .slice(0, 5);

  // Philosophical saturation flag (topics appearing >4 times without variation)
  d.saturated_topics = Object.entries(d.top_topics)
    .filter(([topic, stats]) => stats.count > 4 && stats.identity_score / stats.count < 2)
    .map(([topic]) => topic);
});

const contentGaps = {
  Health: ['nervous_system_regulation', 'metabolic_flexibility', 'circadian_optimization', 'somatic_intelligence'],
  Wealth: ['attention_economics', 'leverage_thinking', 'market_timing', 'compound_decisions'],
  Wisdom: ['temporal_perspective', 'meaning_creation', 'death_contemplation', 'symbolic_thinking']
};

return {
  analysis_date: new Date().toISOString().split('T')[0],
  by_pillar: byPillar,
  content_gaps: contentGaps,
  total_analyzed: data.length
};

const aiOutput = $input.first().json.output;
const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)```/) || aiOutput.match(/\{[\s\S]*"week_of"[\s\S]*\}/);
if (!jsonMatch) return {error: 'No strategy JSON'};

const strategy = JSON.parse(jsonMatch[0].replace(/```json|```/g, '').trim());

return {
  strategy_id: 'STRAT-' + Date.now(),
  created_at: new Date().toISOString(),
  week_of: strategy.week_of,
  strategy_summary: strategy.strategy_summary,
  content_pillars: strategy.content_pillars,
  weekly_goal: strategy.weekly_goal,
  philosophy_refinement: strategy.philosophy_refinement,
  status: 'approved'
};

const aiOutput = $input.first().json.output;

try {
  const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)```/) || aiOutput.match(/\{[\s\S]*"master_content"[\s\S]*\}/);
  if (!jsonMatch) return {error: 'No master content JSON found', raw: aiOutput.substring(0, 500)};

  let jsonStr = jsonMatch[0].replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(jsonStr);
  const masterContent = parsed.master_content;

  // Validate required fields
  const required = ['headline', 'hook', 'core_script', 'key_points', 'explicit_tradeoff', 'faceless_video_specs'];
  const missing = required.filter(f => !masterContent[f]);
  if (missing.length > 0) return {error: 'Missing required fields', missing_fields: missing};

  const calendarData = $('Parse Content Plan').item.json;

  return {
    content_id: 'CONTENT-' + Date.now(),
    calendar_id: calendarData.calendar_id,
    strategy_id: calendarData.strategy_id,
    created_at: new Date().toISOString(),
    scheduled_date: calendarData.scheduled_date,
    pillar: calendarData.pillar,
    topic: calendarData.topic,
    topic_readable: calendarData.topic_readable,
    headline: masterContent.headline,
    hook: masterContent.hook,
    core_script: masterContent.core_script,
    key_points: masterContent.key_points,
    explicit_tradeoff: masterContent.explicit_tradeoff,
    faceless_video_specs: masterContent.faceless_video_specs,
    cta: masterContent.cta,
    long_form_outline: masterContent.long_form_outline,
    hashtag_suggestions: masterContent.hashtag_suggestions,
    seo_keywords: masterContent.seo_keywords,
    language_seed: masterContent.language_seed,
    content_pillar: masterContent.content_pillar,
    master_content_json: masterContent,
    status: 'generated'
  };
} catch (error) {
  return {error: 'Parse failed: ' + error.message, raw: aiOutput.substring(0, 500)};
}

const scheduledDate = $input.first().json.scheduled_date;

const optimalTimes = {
  tiktok: ['06:00', '12:00', '19:00'],
  instagram_reel: ['06:00', '12:00', '19:00'],
  youtube_short: ['06:00', '12:00', '19:00'],
  snapchat_spotlight: ['06:00', '12:00', '19:00'],
  instagram_carousel: ['11:00', '14:00', '20:00'],
  instagram_story: ['08:00', '12:00', '21:00'],
  snapchat_story: ['08:00', '13:00', '21:00'],
  youtube_long: ['14:00', '18:00'],
  twitter_x: ['08:00', '12:00', '17:00'],
  linkedin: ['08:00', '12:00', '17:00'],
  facebook: ['13:00', '19:00'],
  reddit: ['07:00', '12:00', '20:00'],
  blog: ['10:00'],
  newsletter: ['06:00'],
  pinterest: ['14:00', '20:00']
};

const postingTimes = {};
Object.keys(optimalTimes).forEach(platform => {
  const time = optimalTimes[platform][0];
  postingTimes[platform] = {
    date: scheduledDate,
    time: time,
    datetime_iso: `${scheduledDate}T${time}:00-05:00`,
    timezone: 'America/New_York'
  };
});

return {
  content_id: $input.first().json.content_id,
  pillar: $input.first().json.pillar,
  posting_times: postingTimes
};

const aiOutput = $input.first().json.output;

try {
  const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)```/) || aiOutput.match(/\{[\s\S]*"adaptations"[\s\S]*\}/);
  if (!jsonMatch) return {error: 'No adaptations JSON', raw: aiOutput.substring(0, 500)};

  let jsonStr = jsonMatch[0].replace(/```json|```/g, '').trim();
  const parsed = JSON.parse(jsonStr);
  const adaptations = parsed.adaptations;

  const required = ['tiktok', 'instagram_reel', 'youtube_short', 'snapchat_spotlight', 'instagram_carousel', 'instagram_story', 'snapchat_story', 'youtube_long', 'twitter_x', 'linkedin', 'facebook', 'reddit', 'blog', 'newsletter', 'pinterest'];
  const missing = required.filter(p => !adaptations[p]);

  if (missing.length > 0) return {error: 'Missing platforms', missing_platforms: missing};

  const masterData = $('Parse Master Content JSON').item.json;

  return {
    adaptation_id: 'ADAPT-' + Date.now(),
    content_id: masterData.content_id,
    pillar: masterData.pillar,
    scheduled_date: masterData.scheduled_date,
    created_at: new Date().toISOString(),
    adaptations: adaptations,
    platforms_count: Object.keys(adaptations).length,
    status: 'ready_for_distribution'
  };
} catch (error) {
  return {error: 'Parse failed: ' + error.message, raw: aiOutput.substring(0, 500)};
}

