const pillar = $json.pillar;

// Pillar-specific color schemes for visual identity
const pillarDesign = {
  Health: {
    primary_color: '#0EA5E9', // Cyan/blue
    secondary_color: '#06B6D4',
    background: '#0F172A', // Dark navy
    text_color: '#FFFFFF',
    accent: '#38BDF8',
    font: 'Inter, sans-serif',
    style: 'Clean, scientific, high-contrast'
  },
  Wealth: {
    primary_color: '#F59E0B', // Gold
    secondary_color: '#D97706',
    background: '#0A0A0A', // Pure black
    text_color: '#FFFFFF',
    accent: '#FCD34D',
    font: 'Montserrat, sans-serif',
    style: 'Bold, professional, premium'
  },
  Wisdom: {
    primary_color: '#9333EA', // Purple
    secondary_color: '#7C3AED',
    background: '#FDF4ED', // Cream
    text_color: '#1F2937',
    accent: '#C084FC',
    font: 'Crimson Text, serif',
    style: 'Elegant, mysterious, contemplative'
  },
  Integration: {
    primary_color: '#8B5CF6', // Violet (blend)
    secondary_color: '#6366F1',
    background: '#18181B',
    text_color: '#FFFFFF',
    accent: '#A78BFA',
    font: 'Inter, sans-serif',
    style: 'Unified, cohesive'
  }
};

return pillarDesign[pillar] || pillarDesign.Health;

const carouselData = $('Parse Visual Adaptations').item.json.adaptation_data;
const design = $('Get Pillar Design System').item.json;
const pillar = $('Parse Visual Adaptations').item.json.pillar;

// Generate image URLs using a design API (e.g., Canva, Bannerbear, or custom)
const slides = carouselData.slides.map((slide, index) => {
  // Build query string for design API
  const params = new URLSearchParams({
    template: 'carousel_identity_statement',
    slide_number: slide.slide_number,
    main_text: slide.main_text,
    supporting_text: slide.supporting_text,
    bg_color: design.background,
    text_color: design.text_color,
    accent_color: design.primary_color,
    font: design.font,
    pillar: pillar
  });

  return {
    slide_number: slide.slide_number,
    image_url: `https://your-design-api.com/generate?${params.toString()}`,
    main_text: slide.main_text,
    supporting_text: slide.supporting_text
  };
});

return {
  platform: 'instagram_carousel',
  pillar: pillar,
  slides: slides,
  caption: carouselData.caption,
  hashtags: carouselData.hashtags,
  posting_time: carouselData.posting_time,
  adaptation_id: $('Parse Visual Adaptations').item.json.adaptation_id,
  content_id: $('Parse Visual Adaptations').item.json.content_id
};

const storyData = $('Parse Visual Adaptations').item.json.adaptation_data;
const design = $('Get Pillar Design System').item.json;
const pillar = $('Parse Visual Adaptations').item.json.pillar;

// Generate story frames with interaction prompts
const frames = storyData.frames.map((frame, index) => {
  const params = new URLSearchParams({
    template: 'story_interaction',
    frame_number: frame.frame_number,
    text: frame.text,
    visual: frame.visual,
    bg_color: design.background,
    text_color: design.text_color,
    accent_color: design.primary_color,
    pillar: pillar
  });

  return {
    frame_number: frame.frame_number,
    image_url: `https://your-design-api.com/generate?${params.toString()}`,
    text: frame.text,
    duration: frame.duration,
    sticker_type: index === 0 ? 'poll' : (index === storyData.frames.length - 1 ? 'question' : null)
  };
});

// Add interaction prompts that reinforce pillar thinking
const interactionPrompts = {
  Health: {poll: 'Do you track your HRV?', question: 'What health metric changed your life?'},
  Wealth: {poll: 'CAC > LTV?', question: 'What leverage unlocked growth for you?'},
  Wisdom: {poll: 'Death = end or transition?', question: 'What pattern are you noticing lately?'},
  Integration: {poll: 'Optimize one pillar or all three?', question: 'Which pillar needs attention now?'}
};

return {
  platform: 'instagram_story',
  pillar: pillar,
  frames: frames,
  interaction_prompts: interactionPrompts[pillar],
  posting_time: storyData.posting_time,
  adaptation_id: $('Parse Visual Adaptations').item.json.adaptation_id,
  content_id: $('Parse Visual Adaptations').item.json.content_id
};

const storyData = $('Parse Visual Adaptations').item.json.adaptation_data;
const pillar = $('Parse Visual Adaptations').item.json.pillar;

// Snapchat Stories are intentionally more raw/informal
const frames = storyData.frames.map((frame, index) => {
  // Use simpler design, less polished than Instagram
  const params = new URLSearchParams({
    template: 'snapchat_raw',
    frame_number: frame.frame_number,
    text: frame.text,
    style: 'casual', // More informal than IG
    pillar: pillar
  });

  return {
    frame_number: frame.frame_number,
    image_url: `https://your-design-api.com/generate?${params.toString()}`,
    text: frame.text,
    duration: frame.duration
  };
});

return {
  platform: 'snapchat_story',
  pillar: pillar,
  frames: frames,
  posting_time: storyData.posting_time,
  adaptation_id: $('Parse Visual Adaptations').item.json.adaptation_id,
  content_id: $('Parse Visual Adaptations').item.json.content_id
};

const adaptations = JSON.parse($input.first().json.adaptations_json);
const pillar = $input.first().json.pillar;
const platforms = JSON.parse($('Extract Webhook Data3').item.json.platforms);

return platforms.map(platform => ({
  platform: platform,
  pillar: pillar,
  adaptation_id: $input.first().json.adaptation_id,
  content_id: $input.first().json.content_id,
  adaptation_data: adaptations[platform]
}));

const twitterData = $input.first().json.adaptation_data;
const pillar = $input.first().json.pillar;

// Validate: Wealth posts must reference execution or consequence
if (pillar === 'Wealth') {
  const hasExecution = twitterData.thread.some(t => 
    t.text.match(/execut|ship|deploy|launch|build|scale/i) || 
    t.text.match(/consequence|result|outcome|ROI|impact/i)
  );
  if (!hasExecution) {
    return {
      error: 'Wealth post missing execution or consequence reference',
      pillar: pillar,
      platform: 'twitter_x'
    };
  }
}

// Validate: Wisdom posts must ask a real question
if (pillar === 'Wisdom') {
  const hasQuestion = twitterData.thread.some(t => t.text.includes('?'));
  if (!hasQuestion) {
    return {
      error: 'Wisdom post missing real question (cannot preach)',
      pillar: pillar,
      platform: 'twitter_x'
    };
  }
}

return {
  platform: 'twitter_x',
  pillar: pillar,
  thread: twitterData.thread,
  standalone_tweet: twitterData.standalone_tweet,
  posting_time: twitterData.posting_time,
  adaptation_id: $input.first().json.adaptation_id,
  content_id: $input.first().json.content_id
};

const thread = $('Validate & Format Twitter/X').item.json.thread;
const firstTweetId = $input.first().json.data.id;

if (thread.length === 1) {
  return {thread_complete: true, tweet_count: 1};
}

// Build remaining tweets as replies
return thread.slice(1).map((tweet, index) => ({
  text: tweet.text,
  reply_to: index === 0 ? firstTweetId : null, // Will chain in next node
  tweet_number: index + 2
}));

const linkedinData = $input.first().json.adaptation_data;
const pillar = $input.first().json.pillar;

// Validate: Wealth posts must reference execution or consequence
if (pillar === 'Wealth') {
  const hasExecution = linkedinData.post.match(/execut|ship|deploy|launch|build|scale/i) || 
                       linkedinData.post.match(/consequence|result|outcome|ROI|impact/i);
  if (!hasExecution) {
    return {
      error: 'Wealth post missing execution or consequence reference',
      pillar: pillar,
      platform: 'linkedin'
    };
  }
}

// Validate: Wisdom posts must ask a real question
if (pillar === 'Wisdom') {
  const hasQuestion = linkedinData.post.includes('?');
  if (!hasQuestion) {
    return {
      error: 'Wisdom post missing real question (cannot preach)',
      pillar: pillar,
      platform: 'linkedin'
    };
  }
}

return {
  platform: 'linkedin',
  pillar: pillar,
  post: linkedinData.post,
  hook_line: linkedinData.hook_line,
  posting_time: linkedinData.posting_time,
  adaptation_id: $input.first().json.adaptation_id,
  content_id: $input.first().json.content_id
};

const facebookData = $input.first().json.adaptation_data;
