const pinterestData = $input.first().json.adaptation_data;
const pillar = $input.first().json.pillar;
const design = $('Get Pillar Design System').item.json || {
  Health: {primary_color: '#0EA5E9'},
  Wealth: {primary_color: '#F59E0B'},
  Wisdom: {primary_color: '#9333EA'}
}[pillar];

// Generate vertical pin image (1000x1500) with text overlay
const params = new URLSearchParams({
  template: 'pinterest_vertical',
  text_overlay: pinterestData.image_text_overlay,
  bg_color: design.primary_color,
  pillar: pillar,
  width: 1000,
  height: 1500
});

const pinImageUrl = `https://your-design-api.com/generate?${params.toString()}`;

return {
  platform: 'pinterest',
  pillar: pillar,
  pin_title: pinterestData.pin_title,
  pin_description: pinterestData.pin_description,
  board_suggestions: pinterestData.board_suggestions,
  image_url: pinImageUrl,
  link_url: `https://your-blog.com/articles/${$('Build Blog Article (Product Seeds)').item.json.slug}`,
  posting_time: pinterestData.posting_time,
  adaptation_id: $input.first().json.adaptation_id,
  content_id: $input.first().json.content_id
};

const publishedContent = $input.all().map(i => i.json);

// Group by platform for API calls
const byPlatform = {
  tiktok: [],
  instagram_reel: [],
  instagram_carousel: [],
  instagram_story: [],
  youtube_short: [],
  youtube_long: [],
  snapchat_spotlight: [],
  snapchat_story: [],
  twitter_x: [],
  linkedin: [],
  facebook: [],
  reddit: [],
  blog: [],
  newsletter: [],
  pinterest: []
};

publishedContent.forEach(post => {
  if (byPlatform[post.platform]) {
    byPlatform[post.platform].push(post);
  }
});

return Object.entries(byPlatform)
  .filter(([platform, posts]) => posts.length > 0)
  .map(([platform, posts]) => ({
    platform: platform,
    posts: posts,
    post_ids: posts.map(p => p.post_id)
  }));

const platform = $('Group by Platform').item.json.platform;
const apiResponse = $input.first().json;
const posts = $('Group by Platform').item.json.posts;

let metricsArray = [];

// Platform-specific metric extraction
if (platform === 'tiktok') {
  metricsArray = apiResponse.data.videos.map(video => ({
    post_id: video.id,
    views: video.view_count,
    likes: video.like_count,
    comments: video.comment_count,
    shares: video.share_count,
    saves: 0, // TikTok doesn't expose saves via API
    new_followers: 0 // Estimate from engagement
  }));
} else if (platform.includes('instagram')) {
  metricsArray = apiResponse.data.map(insight => ({
    post_id: insight.id,
    views: insight.impressions,
    likes: insight.engagement,
    comments: 0, // Requires separate call
    shares: 0,
    saves: insight.saves || 0,
    new_followers: insight.profile_visits || 0
  }));
} else if (platform.includes('youtube')) {
  metricsArray = apiResponse.rows.map(row => ({
    post_id: row[0],
    views: row[1],
    likes: row[2],
    comments: row[3],
    shares: row[4],
    saves: 0,
    new_followers: row[5],
    avg_view_duration: row[6] // Repeat viewer signal
  }));
} else if (platform === 'twitter_x') {
  metricsArray = apiResponse.data.map(tweet => ({
    post_id: tweet.id,
    views: tweet.public_metrics.impression_count,
    likes: tweet.public_metrics.like_count,
    comments: tweet.public_metrics.reply_count,
    shares: tweet.public_metrics.retweet_count,
    saves: 0, // Twitter doesn't expose bookmarks
    new_followers: 0
  }));
} else if (platform === 'linkedin') {
  metricsArray = apiResponse.elements.map(stat => ({
    post_id: stat.ugcPost,
    views: stat.totalShareStatistics.impressionCount,
    likes: stat.totalShareStatistics.likeCount,
    comments: stat.totalShareStatistics.commentCount,
    shares: stat.totalShareStatistics.shareCount,
    saves: 0,
    new_followers: 0
  }));
}

// Calculate engagement score (identity-weighted)
return metricsArray.map(metrics => {
  const post = posts.find(p => p.post_id === metrics.post_id);

  // Identity signal weighting
  const identityScore = (
    (metrics.saves * 5) +           // Save = strong intent
    (metrics.comments * 3) +        // Comment = engagement
    (metrics.new_followers * 10) +  // Follow = identity alignment
    (metrics.shares * 2) +          // Share = endorsement
    (metrics.likes * 1)             // Like = weak signal
  );

  const engagementRate = metrics.views > 0 ? (identityScore / metrics.views) * 100 : 0;
  const engagementScore = Math.min(100, Math.round(identityScore / 10));

  return {
    content_id: post?.content_id,
    platform: platform,
    post_id: metrics.post_id,
    views: metrics.views,
    likes: metrics.likes,
    comments: metrics.comments,
    shares: metrics.shares,
    saves: metrics.saves,
    new_followers: metrics.new_followers,
    repeat_viewers: metrics.avg_view_duration || 0,
    engagement_rate: Math.round(engagementRate * 100) / 100,
    engagement_score: engagementScore,
    identity_signals: {
      saves: metrics.saves,
      comments: metrics.comments,
      new_followers: metrics.new_followers,
      repeat_viewers: metrics.avg_view_duration || 0
    },
    created_at: new Date().toISOString()
  };
});

const data = $input.all().map(i => i.json);

const byPillar = {
  Health: {posts: [], total_score: 0, identity_total: 0, platforms: {}, topics: {}, flags: {}},
  Wealth: {posts: [], total_score: 0, identity_total: 0, platforms: {}, topics: {}, flags: {}},
  Wisdom: {posts: [], total_score: 0, identity_total: 0, platforms: {}, topics: {}, flags: {}},
  Integration: {posts: [], total_score: 0, identity_total: 0, platforms: {}, topics: {}, flags: {}}
};

data.forEach(post => {
  const pillar = post.pillar;
  if (!byPillar[pillar]) return;

  byPillar[pillar].posts.push(post);
  byPillar[pillar].total_score += post.engagement_score;

  // Identity signals
  const identitySignals = JSON.parse(post.identity_signals || '{}');
  byPillar[pillar].identity_total += (identitySignals.saves || 0) + (identitySignals.new_followers || 0);

  // Platform performance
  if (!byPillar[pillar].platforms[post.platform]) {
    byPillar[pillar].platforms[post.platform] = {total: 0, count: 0, identity: 0};
  }
  byPillar[pillar].platforms[post.platform].total += post.engagement_score;
  byPillar[pillar].platforms[post.platform].count++;
  byPillar[pillar].platforms[post.platform].identity += (identitySignals.saves || 0) + (identitySignals.new_followers || 0);

  // Topic performance
  if (!byPillar[pillar].topics[post.topic]) {
    byPillar[pillar].topics[post.topic] = {total: 0, count: 0};
  }
  byPillar[pillar].topics[post.topic].total += post.engagement_score;
  byPillar[pillar].topics[post.topic].count++;

  // Philosophy flag tracking
  if (!byPillar[pillar].flags[post.philosophy_flag]) {
    byPillar[pillar].flags[post.philosophy_flag] = {total: 0, count: 0};
  }
  byPillar[pillar].flags[post.philosophy_flag].total += post.engagement_score;
  byPillar[pillar].flags[post.philosophy_flag].count++;
});

// Calculate averages and detect patterns
Object.keys(byPillar).forEach(pillar => {
  const d = byPillar[pillar];
  d.avg_score = d.posts.length > 0 ? Math.round(d.total_score / d.posts.length) : 0;
  d.identity_avg = d.posts.length > 0 ? Math.round(d.identity_total / d.posts.length) : 0;

  // Best platforms
  d.best_platforms = Object.entries(d.platforms)
    .map(([platform, stats]) => ({
      platform,
      avg_score: Math.round(stats.total / stats.count),
      identity_rate: Math.round(stats.identity / stats.count)
    }))
    .sort((a, b) => b.identity_rate - a.identity_rate)
    .slice(0, 3);

  // Top topics
  d.top_topics = Object.entries(d.topics)
    .map(([topic, stats]) => ({topic, avg_score: Math.round(stats.total / stats.count)}))
    .sort((a, b) => b.avg_score - a.avg_score)
    .slice(0, 3);

  // Philosophy flag performance
  d.flag_performance = Object.entries(d.flags)
    .map(([flag, stats]) => ({flag, avg_score: Math.round(stats.total / stats.count)}))
    .sort((a, b) => b.avg_score - a.avg_score);
});

// Detect strongest/weakest pillar
const pillarRankings = Object.entries(byPillar)
  .filter(([pillar]) => pillar !== 'Integration')
  .map(([pillar, data]) => ({pillar, identity_avg: data.identity_avg}))
  .sort((a, b) => b.identity_avg - a.identity_avg);

const strongestPillar = pillarRankings[0]?.pillar;
const weakestPillar = pillarRankings[pillarRankings.length - 1]?.pillar;

// Detect generic drift (low identity signals despite high engagement)
const genericDriftPillars = Object.entries(byPillar)
  .filter(([pillar, data]) => {
    const ratio = data.identity_avg / (data.avg_score || 1);
    return ratio < 0.3 && data.posts.length > 2; // <30% identity signals = generic
  })
  .map(([pillar]) => pillar);

return {
  week_of: $today.minus({days: 7}).toISODate(),
  by_pillar: byPillar,
  strongest_pillar: strongestPillar,
  weakest_pillar: weakestPillar,
  generic_drift: genericDriftPillars,
  total_posts: data.length
};

const aiOutput = $input.first().json.output;
const jsonMatch = aiOutput.match(/```json\s*([\s\S]*?)```/) || aiOutput.match(/\{[\s\S]*"weekly_intelligence"[\s\S]*\}/);
if (!jsonMatch) return {error: 'No intelligence JSON'};

const intelligence = JSON.parse(jsonMatch[0].replace(/```json|```/g, '').trim());

return {
  analysis_id: 'ANALYSIS-' + Date.now(),
  week_of: $('Aggregate by Pillar (Detect Drift)').item.json.week_of,
  created_at: new Date().toISOString(),
  weekly_intelligence: intelligence.weekly_intelligence,
  status: 'ready_for_feedback'
};
